import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Weave (#1): a third-party plugin registered ONCE, globally, by name. It
// never touches internal state: it subscribes to the 'draw' lifecycle hook
// and paints into its own sandboxed layer using the api (scales, data, theme,
// emit). Activate it per-chart via the top-level plugins array.
ApexCharts.registerPlugin({
  name: 'mean-line',
  apiVersion: 1,
  setup(api) {
    api.on('draw', function (ctx) {
      var scales = ctx.scales
      var data = ctx.data
      if (!scales || !data || !data.length) return

      var layer = api.layer({ z: 'front' })
      layer.clear()

      var series = data.filter(function (s) {
        return !s.hidden
      })[0]
      if (!series || !series.points.length) return

      var sum = 0
      var n = 0
      series.points.forEach(function (p) {
        if (p.y != null) {
          sum += p.y
          n++
        }
      })
      if (!n) return

      var mean = sum / n
      var y = scales.y(mean)
      var accent = api.theme.token('accent') || '#0e9d9a'

      layer.line({
        x1: 0,
        y1: y,
        x2: scales.gridWidth,
        y2: y,
        stroke: accent,
        width: 2,
        dash: 5,
      })
      layer.text({
        x: scales.gridWidth - 6,
        y: y - 7,
        text: 'mean ' + mean.toFixed(1),
        color: accent,
        size: 12,
        anchor: 'end',
        weight: 600,
      })

      // hand the computed value back to the page via a custom event; it
      // fires namespaced as 'plugin:mean-line:meanComputed' so plugin events
      // can never collide with the chart's internal lifecycle events
      api.emit('meanComputed', { value: mean })
    })
  },
})

function randomSeries() {
  var d = []
  for (var i = 0; i < 8; i++) d.push(Math.round(20 + Math.random() * 80))
  return d
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Value', data: [42, 61, 38, 74, 55, 48, 67, 52] }],
    options: {
      chart: {
        id: 'weaveChart',
        height: 380,
        type: 'line',
        animations: { enabled: true },
        toolbar: { show: false },
      },
      colors: ['#0e9d9a'],
      stroke: { curve: 'smooth', width: 3 },
      markers: { size: 4 },
      title: { text: 'Series with a plugin-drawn mean line', align: 'left' },
      subtitle: {
        text: 'The mean line comes from a Weave plugin, not the chart config',
        align: 'left',
      },
      xaxis: { categories: [1, 2, 3, 4, 5, 6, 7, 8] },
      plugins: [{ name: 'mean-line' }],
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id. Poll until it exists, then wire the same UI the vanilla build
    // does. (The mean-line plugin is registered ONCE in the shared head script,
    // before any chart is created, and randomSeries lives there too.)
    let chart
    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('weaveChart')
      if (!chart) return
      window.clearInterval(timer)

      const readout = document.getElementById('readout')

      chart.addEventListener('plugin:mean-line:meanComputed', (c, payload) => {
        const detail =
          payload && payload.value != null
            ? payload
            : c && c.value != null
              ? c
              : null
        const v = detail ? detail.value : null
        if (v != null) {
          readout.innerHTML =
            'plugin mean-line emitted: <b>mean = ' + v.toFixed(1) + '</b>'
        }
      })

      document.getElementById('newData').addEventListener('click', () => {
        chart.updateSeries([{ name: 'Value', data: randomSeries() }])
      })
    }, 50)

    return () => {
      window.clearInterval(timer)
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <button id="newData">New data</button>
          <span className="readout" id="readout">
            Mean line drawn by the plugin. Press New data to recompute.
          </span>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={380}
        />
      </div>

      <div className="panel">
        <div className="note">
          The dashed mean line is not part of the chart: it is drawn by a plugin
          registered with{' '}
          <code>ApexCharts.registerPlugin(&#123; name, setup &#125;)</code> and
          activated via <code>plugins: [&#123; name: 'mean-line' &#125;]</code>.
          On every
          <code>draw</code> hook the plugin reads <code>api.data</code>,
          converts the mean to a pixel with <code>api.scales.y()</code>, paints
          into its own
          <code>api.layer()</code>, and reports the value back through
          <code>api.emit()</code>. Press New data: the plugin recomputes and
          redraws.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

